		ActionType   string  `json:"action_type"`
		Total        int     `json:"total"`
		SuccessCount int     `json:"success_count"`
		AvgDuration  float64 `json:"avg_duration"`
	}

	var rawResults []rawResult
	_, err := o.Raw(query, args...).QueryRows(&rawResults)
	if err != nil {
