	placeholders := make([]string, len(departments))
	args := make([]interface{}, 0, len(departments))
	for i, d := range departments {
		placeholders[i] = "?"
		args = append(args, d)
	}

	query := fmt.Sprintf(
		`SELECT %s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
		FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY %s`,
		columnRef,
		strings.Join(placeholders, ", "),
		columnRef,
	)

	var maps []orm.Params
	_, err := o.Raw(query, args...).Values(&maps)
	if err != nil {
		return nil, err
	}

	results := make([]map[string]interface{}, 0, len(maps))
	for _, m := range maps {
		result := make(map[string]interface{})
		result["group_value"] = m["group_value"]
		result["user_count"] = m["user_count"]
		result["total_activities"] = m["total_activities"]
		results = append(results, result)
	}

	return results, nil
}

