	return "user_activity"
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	placeholders := make([]string, len(usernames))
	args := make([]interface{}, 0, len(usernames)+2)
	for i, u := range usernames {
		placeholders[i] = "?"
		args = append(args, u)
	}

	query := fmt.Sprintf(
		`SELECT u.display_name, a.action_type, COUNT(*) as total, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration
		FROM user_activity a JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s)`,
		strings.Join(placeholders, ", "),
	)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " AND a.created_at >= ? AND a.created_at <= ?"
	args = append(args, startDate, endDate)

	query += " GROUP BY u.display_name, a.action_type"

	var results []UserActivitySummary
	var rawResults []struct {
		DisplayName  string  `json:"display_name"`
		ActionType   string  `json:"action_type"`
		Total        int     `json:"total"`
		SuccessCount int     `json:"success_count"`
		AvgDuration  float64 `json:"avg_duration"`
	}

	_, err := o.Raw(query, args...).QueryRows(&rawResults)
	if err != nil {
		return nil, err
	}

	for _, r := range rawResults {
		results = append(results, UserActivitySummary{
			DisplayName:  r.DisplayName,
			ActionType:   r.ActionType,
			TotalActions: r.Total,
			SuccessCount: r.SuccessCount,
			AvgDuration:  r.AvgDuration,
		})
	}

	if results == nil {
		results = []UserActivitySummary{}
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField to prevent SQL injection
	var columnName string
	switch groupByField {
	case "department":
		columnName = "u.department"
	case "role":
		columnName = "u.role"
	case "display_name":
		columnName = "u.display_name"
	default:
		return nil, fmt.Errorf("invalid groupByField: %s, must be one of: department, role, display_name", groupByField)
	}

	placeholders := make([]string, len(departments))
	args := make([]interface{}, 0, len(departments))
	for i, d := range departments {
		placeholders[i] = "?"
		args = append(args, d)
	}

	query := fmt.Sprintf(
		`SELECT %s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
		FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY %s`,
		columnName,
		strings.Join(placeholders, ", "),
		columnName,
	)

	var rawResults []struct {
		GroupValue      string `json:"group_value"`
		UserCount       int    `json:"user_count"`
		TotalActivities int    `json:"total_activities"`
	}

	_, err := o.Raw(query, args...).QueryRows(&rawResults)
	if err != nil {
		return nil, err
	}

	results := make([]map[string]interface{}, 0, len(rawResults))
	for _, r := range rawResults {
		m := map[string]interface{}{
			"group_value":      r.GroupValue,
			"user_count":       r.UserCount,
			"total_activities": r.TotalActivities,
		}
		results = append(results, m)
	}

	return results, nil
}

